1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Basic premium calculation ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const out = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(out.results[0]).toEqual({ premium: 5 });
12	  });
13	  it("single sword (no modifiers, newcomer first contract) → 100 base + 10 first + 5 fee = 115 G", () => {
14	    const out = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
17	    });
18	    expect(out.results[0]).toEqual({ premium: 115 });
19	  });
20	  it("single amulet (no modifiers, newcomer first contract) → 60 + 6 + 5 = 71 G", () => {
21	    const out = runScenario({
22	      customer: { yearsWithMHPCO: 0 },
23	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
24	    });
25	    expect(out.results[0]).toEqual({ premium: 71 });
26	  });
27	  it("single staff (no modifiers, newcomer first contract) → 80 + 8 + 5 = 93 G", () => {
28	    const out = runScenario({
29	      customer: { yearsWithMHPCO: 0 },
30	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
31	    });
32	    expect(out.results[0]).toEqual({ premium: 93 });
