35	    const out = runScenario({
36	      customer: { yearsWithMHPCO: 0 },
37	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
38	    });
39	    expect(out.results[0]).toEqual({ premium: 49 });
40	  });
41	
42	  // --- Components and block discount ---
43	  it("2 runes → base 50 G (newcomer: 50 + 5 + 5 fee = 60 G)", () => {
44	    const out = runScenario({
45	      customer: { yearsWithMHPCO: 0 },
46	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
