58	    const out = runScenario({
59	      customer: { yearsWithMHPCO: 0 },
60	      steps: [
61	        {
62	          op: "quote",
63	          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
64	        },
65	      ],
66	    });
67	    expect(out.results[0]).toEqual({ premium: 115 });
