69	  it("7 runes → base 175 G; total 175 + 17.5 + 5 = 197.5 → rounded up to 198", () => {
70	    const out = runScenario({
71	      customer: { yearsWithMHPCO: 0 },
72	      steps: [
73	        {
74	          op: "quote",
75	          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
