81	  it("2 runes + 1 moonstone → base 75 G; total 88 G", () => {
82	    const out = runScenario({
83	      customer: { yearsWithMHPCO: 0 },
84	      steps: [
85	        {
86	          op: "quote",
87	          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
88	        },
89	      ],
90	    });
91	    expect(out.results[0]).toEqual({ premium: 88 });
