93	  it("3 runes + 3 moonstones → base 120 G (two blocks); total 137 G", () => {
94	    const out = runScenario({
95	      customer: { yearsWithMHPCO: 0 },
96	      steps: [
97	        {
98	          op: "quote",
99	          items: [
100	            { type: "rune" }, { type: "rune" }, { type: "rune" },
101	            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
