108	
109	  // --- Item-specific modifiers ---
110	  it("cursed sword newcomer first contract → 165 G", () => {
111	    const out = runScenario({
112	      customer: { yearsWithMHPCO: 0 },
113	      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
