131	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
132	
133	  // --- Policy-wide modifiers ---
134	  it.todo("customer with exactly 2 years → loyalty discount applies");
135	  it.todo("second contract → follow-up discount applies");
136	
137	  // --- Modifier scope on multi-item policy ---
138	  it.todo("cursed sword + plain amulet → policy base 160 + 50 curse = 210 G before fee/policy-wide");
139	
140	  // --- Rounding ---
141	  it.todo("premium yielding 197.5 G → rounded up to 198 G");
142	  it.todo("payout yielding 350.5 G → rounded down to 350 G");
143	
144	  // --- Integration examples ---
145	  it.todo("newcomer with cursed sword (enchantment 3) → 165 G");
146	  it.todo("long-standing customer (3y) second contract, cursed sword enchantment 7 → 160 G");
147	
148	  // --- Claim: basic and deductible ---
149	  it.todo("regular sword damage 500 G → payout 400 G (full minus deductible)");
150	  it.todo("rune (no enchantment/material) damage 200 G → payout 100 G");
151	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
152	
153	  // --- Claim: enchantment and dragon clauses ---
154	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 G (50% then deductible)");
155	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 G (50% wins, then deductible)");
156	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 G (full, then deductible)");
157	  it.todo("steel sword enchantment 9, damage 1000 → payout 400 G (50% then deductible)");
158	
159	  // --- Multiple items of the same type ---
160	  it.todo("policy with two swords, both damaged → each treated as separate damage with own deductible");
161	  it.todo("damages array has more entries of a type than policy covers → CLI rejects whole claim");
162	
163	  // --- Cap exhaustion ---
164	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
165	  it.todo("cursed sword premium modifiers do not raise cap → cap remains 2000");
166	  it.todo("sword + 3 runes (block) → insurance sum 1750 (block does not reduce insurance sum)");
167	  it.todo("sword cap 2000: two claims of 1500 → first payout 1400 (cap 600), second payout 600 (cap 0)");
168	
169	  // --- Edge cases / CLI errors ---
170	  it.todo("quote with unknown item type → CLI exits non-zero, writes stderr, no results");
171	  it.todo("claim references item not in policy → CLI exits non-zero, writes stderr");
172	  it.todo("claim damage with negative amount → CLI exits non-zero, writes stderr");
173	});
