1	type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	};
7	type Step = { op: "quote"; items: Item[] };
8	type Scenario = {
9	  customer: { yearsWithMHPCO: number };
10	  steps: Step[];
11	};
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const ITEM_BASE: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_BASE = 60;
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	
31	const groupCountsByType = (items: Item[]): Map<string, number> => {
32	  const counts = new Map<string, number>();
33	  for (const item of items) {
34	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
35	  }
36	  return counts;
37	};
38	
39	const baseForGroup = (type: string, count: number): number => {
40	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
41	    return COMPONENT_BLOCK_BASE;
42	  }
43	  return count * ITEM_BASE[type];
44	};
45	
46	const calculatePolicyBase = (items: Item[]): number => {
47	  let total = 0;
48	  for (const [type, count] of groupCountsByType(items)) {
49	    total += baseForGroup(type, count);
50	  }
51	  return total;
52	};
53	
54	const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);
55	
56	const curseSurcharge = (item: Item): number =>
57	  item.cursed ? ITEM_BASE[item.type] * CURSE_SURCHARGE_RATE : 0;
58	
59	const highEnchantmentSurcharge = (item: Item): number =>
60	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
61	    ? ITEM_BASE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
62	    : 0;
63	
64	const ITEM_SURCHARGES: Array<(item: Item) => number> = [
65	  curseSurcharge,
66	  highEnchantmentSurcharge,
67	];
68	
69	const surchargesForItem = (item: Item): number =>
70	  ITEM_SURCHARGES.reduce((sum, surcharge) => sum + surcharge(item), 0);
71	
72	const itemSpecificSurcharges = (items: Item[]): number =>
73	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
74	
75	const quotePremium = ({ items }: Step): number => {
76	  const policyBase = calculatePolicyBase(items);
77	  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
78	  const itemSurcharges = itemSpecificSurcharges(items);
79	  const rawPremium = policyBase + itemSurcharges + firstContractSurcharge + PROCESSING_FEE;
80	  return roundUpInMHPCOsFavor(rawPremium);
81	};
82	
83	export const runScenario = ({ steps }: Scenario): { results: unknown[] } => {
84	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
85	  return { results };
86	};
